import { useState } from "react";

const Card = function ({ cl, children, status }) {
    let backGroundColour;

    switch (status) {
        case "in-progress":
            backGroundColour = "#c3fae8";
            break;
        case "done":
            backGroundColour = "#d0ebff";
            break;
        default:
            backGroundColour = "#fff";
    }
    return (
        <div className={`${cl} card--layout`} style={`background-color:${backGroundColour}`}>
            {children}
        </div>
    );
};
const AddCard = function ({ handleModal }) {
    return (
        <div className="add-card__box">
            <p className="add-card--text">追加</p>
            <button type="button" className="add-card__btn" onClick={handleModal}>
                <svg
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 24 24"
                    fill="currentColor"
                    className="add-card__icon"
                >
                    <path
                        fillRule="evenodd"
                        d="M12 3.75a.75.75 0 0 1 .75.75v6.75h6.75a.75.75 0 0 1 0 1.5h-6.75v6.75a.75.75 0 0 1-1.5 0v-6.75H4.5a.75.75 0 0 1 0-1.5h6.75V4.5a.75.75 0 0 1 .75-.75Z"
                        clipRule="evenodd"
                    />
                </svg>
            </button>
        </div>
    );
};
const TodoCard = function ({ todo, status, onChangeColour }) {
    return (
        <>
            <select
                className="todo-card__select"
                value={status}
                onChange={(e) => onChangeColour(e.target.value)}
            >
                <option value="yet">未着手</option>
                <option value="in-progress">進行中</option>
                <option value="done">完了</option>
            </select>
            <h3>{todo.main}</h3>
            <h5>{todo.sub}</h5>
            <p>{todo.start}</p>
            <p>{todo.deadline}</p>
            <button type="button" className="todo--delete">
                &times;
            </button>
        </>
    );
};

export { Card, AddCard, TodoCard };
